var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오… 오오…!","JPN":"お……おお……！","ENG":"W-whoa...!","TWN":"喔…喔喔…！"},"stage":{"bg":"CAMP","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"지원군이다! 구원 기사단이 우릴 도우러 왔어!","JPN":"援軍だ！　救世騎士団が俺たちを助けに来たんだ！","ENG":"Backup! The Knights of Redemption are here to help us!","TWN":"是援軍！救贖騎士團來救我們了！"},"stage":{"bg":"CAMP","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님! 마을을 막고 있던 괴수들이 물러나고 있습니다!","JPN":"隊長！　村を塞いでいた怪獣たちが退いていきます！","ENG":"Captain! The monsters that were obstructing the village are moving back!","TWN":"隊長! 圍堵村莊的怪獸開始撤退了！"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"지금이 기회입니다. 당장 따라가 놈들의 뒤를 쳐야 합니다!","JPN":"今がチャンスです。今すぐ追いかけて奴らを討ちましょう！","ENG":"Now is our chance. We need to follow them and strike while they're distracted!","TWN":"趁現在！立刻追上去迎擊！"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"진정하고 잘 보도록. 일정한 간격을 둔 사방진으로부터 공격이 뻗어 나오고 있다.","JPN":"落ち着いてよく見ろ。一定の距離を置いて四方から攻撃をしかけている。","ENG":"Calm down and observe. They are attacking from four different directions.","TWN":"冷靜地看清楚，各自間隔一段距離散落在四個方位進行攻擊。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"선발대 구출만이 목적이었다면 저런 식으로 화력을 분산시킬 필요는 없어.","JPN":"先発隊の救出だけが目的なら、あんな風に火力を分散させる必要はない。","ENG":"They wouldn't split up their forces if rescuing the advance party was their only objective.","TWN":"若目的只是要救出先遣隊，沒必要這樣分散火力。"},"stage":{"bg":"CAMP","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"각각의 진으로 병사들을 나눠라! 구원기사단과 합류해, 이곳에서 놈들을 쓰러트린다!","JPN":"各々の陣に兵士を分けろ！　救世騎士団と合流し、ここで奴らを倒す！","ENG":"Split into four groups and head to the four different points! We will join the Knights of Redemption and vanquish the monsters here!","TWN":"把兵力分散到四個方位！與救援騎士團會合，在這裡消滅怪獸！"},"stage":{"bg":"CAMP","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하의 작전대로 흘러가는군요. 제국군의 병력이 넷으로 나뉘었습니다.","JPN":"殿下の作戦どおりですね。帝国軍の兵力が四つに分かれました。","ENG":"It is going according to your plan, Your Highness. The imperial soldiers are divided into four.","TWN":"按照殿下的作戰計劃進行中呢。帝國軍的兵力已分散至四方。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무렴. 인류 최후의 군세가 이 정도도 해주지 않으면 곤란하지.","JPN":"当たり前だ。人類最後の軍勢がこの程度もできないようでは困る。","ENG":"Of course. I'd expect nothing less from the last army of humanity.","TWN":"當然。如果人類最後的軍隊連這點事都辦不到還能做什麼。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"대열이 갖춰지기 전까지 빠져나오는 놈들은 샬롯과 평민이 맡도록.","JPN":"隊列が整うまで、抜け出てくる怪獣はシャーロットと平民が処理しろ。","ENG":"Carlota and peasant, you two are to handle the ones that escape before the line is formed.","TWN":"在隊伍成形前，夏洛特和平民就負責那些試圖逃跑的怪獸。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"작전대로 놈들을 에워싼 뒤, 포위망을 좁혀 단숨에 요격한다!","JPN":"作戦どおりに奴らを囲み、包囲網を狭め一気に迎え撃つ！","ENG":"We shall stay on course! Surround them, move in, and make a swift strike!","TWN":"按照計劃包圍怪獸後，再縮小包圍範圍，一舉殲滅怪獸！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"네!","JPN":"はい！","ENG":"Yes, Your Highness!","TWN":"是！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하. 제게만 별다른 지시가 없으십니다만.","JPN":"殿下。私にだけ特にご指示がありませんが。","ENG":"Your Highness, I seem to be the only one without any orders.","TWN":"殿下，好像只有我沒收到任何指示？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하. 고귀하신 성녀께 궂은 일을 시킬 수야 있나.","JPN":"ハハ。貴い聖女に汚れ仕事をさせるわけにはいくまい。","ENG":"Ha ha. How ever could I make our virtuous Saintess work?","TWN":"哈哈，怎麼能讓高貴的聖女去做這些粗活呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"등산하느라 꽤 피곤해 보이는데, 평소처럼 가만히 서서 병사들 사기나 올리도록.","JPN":"山登りでかなり消耗したと見える。いつものようにじっと立って、兵士の士気でも上げていることだな。","ENG":"You look quite tired after the hike, so why don't you raise the morale of soldiers while standing still like you always do?","TWN":"你應該爬山爬得很累吧？就像平時一樣站著鼓舞士氣就好。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그게 싫으면 끝난 뒤에 평민에게 떨 아양이나 생각해 놓던가 말이다.","JPN":"それが嫌なら、終わった後に平民にどうやって尻尾を振るか考えておくのはどうだ？","ENG":"Or you could come up with ways to court the peasant after the fight.","TWN":"不喜歡的話，就想想結束後怎麼討好平民吧。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하?","JPN":"殿下？","ENG":"Your Highness?","TWN":"殿下？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이……!","JPN":"この……！","ENG":"That...!","TWN":"你這個……！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 능구렁이 같은 황태자 자식이 진짜!","JPN":"この狸皇太子が！","ENG":"That sly, condescending crown prince bastard!","TWN":"狡猾的皇太子！可惡！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아아아!!","JPN":"ワアアアアア！！","ENG":"Woooooh!!","TWN":"哇喔喔喔喔～～！！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"괴수들을 해치웠다! 우리가 이긴 거야!","JPN":"怪獣どもをやっつけたぞ！　俺たちが勝ったんだ！","ENG":"We defeated the monsters! We won!","TWN":"我們打敗怪獸了！我們贏了！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님께서 이곳까지 와 주셨으니, 우리에게 더 이상 패배란 없다!","JPN":"救世主様がいらしたんだ、もう俺たちに負けなどない！","ENG":"The Savior came all the way here for us! We're never going to lose again!","TWN":"現在救贖者大人大人來到在這裡，我們就不會再輸了！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"황태자 전하 만세! 구원자님 만세! 아르카데나 제국 만세!","JPN":"皇太子殿下万歳！　救世主様万歳！　アルカデナ帝国万歳！","ENG":"Long live His Highness! Long live the Savior! Long live Arcadena!","TWN":"皇太子 殿下！救贖者大人大人萬歲！艾爾卡特納帝國萬歲！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};